def _get_db_path():
    if DB_LOCATION != "same_as_exe":
        return DB_LOCATION
    # When frozen as EXE, use folder of the .exe
    # When running as .py, use folder of the script
    if getattr(sys, "frozen", False):
        base = os.path.dirname(sys.executable)
    else:
        base = os.path.dirname(os.path.abspath(__file__))
    return os.path.join(base, "billing.db")

DB_PATH = _get_db_path()

