def next_invoice_no():
    """Generate next invoice number in format TP/YYYY-YY/NNN (sequence resets per FY)."""
    now = datetime.now()
    if now.month >= 4:
        fy = f"{now.year}-{str(now.year + 1)[2:]}"
    else:
        fy = f"{now.year - 1}-{str(now.year)[2:]}"
    
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    # Count invoices in the current fiscal year to get the next sequence number (e.g., TP/2026-27/%)
    pattern = f"TP/{fy}/%"
    c.execute("SELECT COUNT(*) FROM invoices WHERE invoice_no LIKE ?", (pattern,))
    count = c.fetchone()[0]
    conn.close()
    return f"TP/{fy}/{str(count+1).zfill(3)}"

def all_invoices():
    """Returns (id, invoice_no, date, patient_id, patient_name, patient_phone, net_amount)."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    # SQL logic: Prefer i.patient_id. If missing, fallback to name+phone match.
    # Note: SQLite TRIM(LOWER(...)) is basic, but helps.
    c.execute("""
        SELECT
            i.id, i.invoice_no, i.date,
            CASE 
                WHEN i.patient_id IS NOT NULL AND i.patient_id != '' THEN i.patient_id
                ELSE COALESCE(p.id, '-')
            END as display_pid,
            i.patient_name, i.patient_phone, i.net_amount
        FROM invoices i
        LEFT JOIN patients p ON (TRIM(i.patient_phone) = TRIM(p.mobile) AND LOWER(TRIM(i.patient_name)) = LOWER(TRIM(p.name)))
        ORDER BY i.id DESC
    """)
    r = c.fetchall(); conn.close(); return r

def invoices_filtered(from_d=None, to_d=None):
    """Return invoices filtered by date range. Dates are DD-MM-YYYY strings."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    # Convert DD-MM-YYYY to YYYY-MM-DD for SQLite string comparison
    def to_iso(s):
        try:
            parts = s.strip().split("-")
            if len(parts) == 3 and len(parts[2]) == 4:   # DD-MM-YYYY
                return f"{parts[2]}-{parts[1]}-{parts[0]}"
            return s  # already ISO or other
        except: return s
    # Build query — pull the same columns as all_invoices()
    c.execute("""
        SELECT
            i.id, i.invoice_no, i.date,
            CASE 
                WHEN i.patient_id IS NOT NULL AND i.patient_id != '' THEN i.patient_id
                ELSE COALESCE(p.id, '-')
            END as display_pid,
            i.patient_name, i.patient_phone, i.net_amount
        FROM invoices i
        LEFT JOIN patients p ON (TRIM(i.patient_phone) = TRIM(p.mobile) AND LOWER(TRIM(i.patient_name)) = LOWER(TRIM(p.name)))
        ORDER BY i.id DESC
    """)
    rows = c.fetchall(); conn.close()
    if not from_d and not to_d: return rows
    
    result = []
    f_iso = to_iso(from_d) if from_d else None
    t_iso = to_iso(to_d) if to_d else None
    
    for row in rows:
        raw_date = str(row[2]).strip()
        iso = to_iso(raw_date)
        if f_iso and iso < f_iso: continue
        if t_iso and iso > t_iso: continue
        result.append(row)
    return result

def distinct_invoice_months():
    """Return sorted list of (year, month) tuples present in invoices."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT DISTINCT date FROM invoices")
    rows = c.fetchall(); conn.close()
    months = set()
    for (d,) in rows:
        try:
            parts = str(d).strip().split("-")
            if len(parts) == 3 and len(parts[2]) == 4:   # DD-MM-YYYY
                months.add((int(parts[2]), int(parts[1])))
            elif len(parts) == 3 and len(parts[0]) == 4: # YYYY-MM-DD
                months.add((int(parts[0]), int(parts[1])))
        except: pass
    return sorted(months, reverse=True)

def invoice_by_id(inv_id):
    conn = sqlite3.connect(DB_PATH); conn.row_factory = sqlite3.Row
    c = conn.cursor(); c.execute("SELECT * FROM invoices WHERE id=?", (inv_id,))
    row = c.fetchone(); conn.close()
    if row:
        d = dict(row); d["items"] = json.loads(d["items"]); return d
    return None

def get_all_products():
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT id,name,pack_size,price,category FROM products ORDER BY category,name")
    r = c.fetchall(); conn.close(); return r

def get_product_by_name(name):
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT * FROM products WHERE name=? COLLATE NOCASE LIMIT 1", (name,))
    row = c.fetchone(); conn.close()
    if row: return {"id":row[0],"name":row[1],"pack_size":row[2],
                    "price":row[3],"category":row[4]}
    return None

def add_product(name,pack_size,price,category):
    conn=sqlite3.connect(DB_PATH); c=conn.cursor()
    c.execute("INSERT INTO products(name,pack_size,price,category)VALUES(?,?,?,?)",
              (name,pack_size,price,category))
    conn.commit(); conn.close()

def update_product(pid,name,pack_size,price,category):
    conn=sqlite3.connect(DB_PATH); c=conn.cursor()
    c.execute("UPDATE products SET name=?,pack_size=?,price=?,category=? WHERE id=?",
              (name,pack_size,price,category,pid))
    conn.commit(); conn.close()

def delete_product(pid):
    conn=sqlite3.connect(DB_PATH); c=conn.cursor()
    c.execute("DELETE FROM products WHERE id=?",(pid,)); conn.commit(); conn.close()

