def next_patient_id():
    """Generate next TPRNNN patient ID."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT COUNT(*) FROM patients")
    count = c.fetchone()[0]; conn.close()
    return f"TPR{str(count + 1).zfill(3)}"

def all_patients():
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT id,name,age,gender,mobile,email,address FROM patients ORDER BY id")
    r = c.fetchall(); conn.close(); return r

def patients_by_mobile(mobile):
    """Return ALL patients with this mobile (family members allowed)."""
    if not mobile.strip(): return []
    conn = sqlite3.connect(DB_PATH); conn.row_factory = sqlite3.Row
    c = conn.cursor()
    c.execute("SELECT * FROM patients WHERE mobile=? ORDER BY name", (mobile.strip(),))
    rows = c.fetchall(); conn.close()
    return [dict(r) for r in rows]

def patient_by_id(pid):
    conn = sqlite3.connect(DB_PATH); conn.row_factory = sqlite3.Row
    c = conn.cursor()
    c.execute("SELECT * FROM patients WHERE id=?", (pid,))
    row = c.fetchone(); conn.close()
    return dict(row) if row else None

def all_patient_name_labels():
    """Return 'Name (mobile)' labels for autocomplete — includes mobile so same-name patients differ."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT name, mobile FROM patients ORDER BY name")
    rows = c.fetchall(); conn.close()
    labels = []
    for name, mob in rows:
        labels.append(f"{name} ({mob})" if mob else name)
    return labels

def all_patient_mobile_labels():
    """Return a list of unique mobile numbers for phone autocomplete."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT DISTINCT mobile FROM patients WHERE mobile IS NOT NULL AND mobile != '' ORDER BY mobile")
    rows = c.fetchall(); conn.close()
    return [str(r[0]) for r in rows]

def all_patient_ids():
    """Return a list of all patient IDs for autocomplete."""
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("SELECT id FROM patients ORDER BY id")
    rows = c.fetchall(); conn.close()
    return [str(r[0]) for r in rows]

def patients_by_name_contains(text):
    """Search patients whose name contains text (case-insensitive)."""
    conn = sqlite3.connect(DB_PATH); conn.row_factory = sqlite3.Row
    c = conn.cursor()
    c.execute("SELECT * FROM patients WHERE name LIKE ? COLLATE NOCASE ORDER BY name LIMIT 20",
              (f"%{text}%",))
    rows = c.fetchall(); conn.close()
    return [dict(r) for r in rows]

def add_patient(name, age, gender, mobile, email, address):
    pid = next_patient_id()
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    # INSERT (not INSERT OR IGNORE) — same mobile is fine for family members
    c.execute("INSERT INTO patients(id,name,age,gender,mobile,email,address,created_at) VALUES(?,?,?,?,?,?,?,?)",
              (pid, name, age, gender, mobile, email, address, datetime.now().isoformat()))
    conn.commit(); conn.close(); return pid

def update_patient(pid, name, age, gender, mobile, email, address):
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("UPDATE patients SET name=?,age=?,gender=?,mobile=?,email=?,address=? WHERE id=?",
              (name, age, gender, mobile, email, address, pid))
    conn.commit(); conn.close()

def delete_patient(pid):
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("DELETE FROM patients WHERE id=?", (pid,))
    conn.commit(); conn.close()

def upsert_patient_from_invoice(d):
    """Always create/find a patient. Return their ID and update details if needed."""
    mobile = d.get("patient_phone","").strip()
    name   = d.get("patient_name","").strip()
    if not name: return None
    if mobile:
        existing_list = patients_by_mobile(mobile)
        for ex in existing_list:
            if ex["name"].lower() == name.lower():
                # Update existing patient with current info (in case age/address changed)
                update_patient(ex["id"], name, d.get("patient_age",""), 
                               d.get("patient_gender",""), mobile, 
                               d.get("patient_email",""), d.get("patient_address",""))
                return ex["id"]
    pid = add_patient(name, d.get("patient_age",""), d.get("patient_gender",""),
                      mobile, d.get("patient_email",""), d.get("patient_address",""))
    return pid


def save_invoice(d):
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()

    c.execute("""INSERT INTO invoices
        (invoice_no,date,patient_id,patient_name,patient_phone,patient_email,patient_age,patient_gender,
         patient_address,doctor,items,subtotal,discount_pct,discount_amt,round_off,net_amount,
         payment_mode,paid_amount,remarks,created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (d["invoice_no"],d["date"],d.get("patient_id",""),d["patient_name"],d.get("patient_phone",""),
         d.get("patient_email",""),d.get("patient_age",""),d.get("patient_gender",""),
         d.get("patient_address",""),d["doctor"],json.dumps(d["items"]),
         d["subtotal"],d["discount_pct"],d["discount_amt"],d["round_off"],d["net_amount"],
         d.get("payment_mode","Cash"),d.get("paid_amount",0),
         d.get("remarks",""), datetime.now().isoformat()))
    conn.commit(); conn.close()

def update_invoice(d, inv_id):
    if not inv_id: return
    conn = sqlite3.connect(DB_PATH); c = conn.cursor()
    c.execute("""UPDATE invoices SET
        invoice_no=?, date=?, patient_id=?, patient_name=?, patient_phone=?, patient_email=?,
        patient_age=?, patient_gender=?, patient_address=?, doctor=?, items=?,
        subtotal=?, discount_pct=?, discount_amt=?, round_off=?, net_amount=?,
        payment_mode=?, paid_amount=?, remarks=?
        WHERE id=?""",
        (d["invoice_no"],d["date"],d.get("patient_id",""),d["patient_name"],d.get("patient_phone",""),
         d.get("patient_email",""),d.get("patient_age",""),d.get("patient_gender",""),
         d.get("patient_address",""),d["doctor"],json.dumps(d["items"]),
         d["subtotal"],d["discount_pct"],d["discount_amt"],d["round_off"],d["net_amount"],
         d.get("payment_mode","Cash"),d.get("paid_amount",0),
         d.get("remarks",""), inv_id))
    conn.commit(); conn.close()

