def _xl_style(ws, header_row, data_rows, sum_col=None):
    """Apply styling to an openpyxl worksheet."""
    from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
    from openpyxl.utils import get_column_letter
    hdr_fill  = PatternFill("solid", fgColor="1A1A2E")
    hdr_font  = Font(bold=True, color="FFFFFF", size=11)
    hdr_align = Alignment(horizontal="center", vertical="center")
    thin   = Side(style="thin", color="CCCCCC")
    border = Border(left=thin, right=thin, top=thin, bottom=thin)
    for cell in ws[header_row]:
        cell.fill = hdr_fill; cell.font = hdr_font
        cell.alignment = hdr_align; cell.border = border
    ws.row_dimensions[header_row].height = 22
    alt_fill = PatternFill("solid", fgColor="F2F6FF")
    for i, row_idx in enumerate(data_rows):
        for cell in ws[row_idx]:
            cell.font = Font(size=10); cell.border = border
            cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
            if i % 2 == 1: cell.fill = alt_fill
        ws.row_dimensions[row_idx].height = 18
    if sum_col is not None and data_rows:
        sum_row_idx = max(data_rows) + 1
        for col_idx in range(1, ws.max_column + 1):
            cell = ws.cell(sum_row_idx, col_idx)
            cell.fill = PatternFill("solid", fgColor="E8F5E9")
            cell.font = Font(bold=True, size=11, color="145214")
            cell.border = border
            cell.alignment = Alignment(horizontal="center", vertical="center")
        ws.row_dimensions[sum_row_idx].height = 22
    for col in ws.columns:
        col_letter = get_column_letter(col[0].column)
        max_len = max((len(str(cell.value)) for cell in col if cell.value), default=8)
        ws.column_dimensions[col_letter].width = min(max(max_len + 3, 10), 50)

def export_invoices_excel(parent_widget, rows=None):
    """Export invoices to Excel. If rows is provided (from current filter), export those only."""
    try:
        from openpyxl import Workbook
        from openpyxl.utils import get_column_letter
    except ImportError:
        QMessageBox.critical(parent_widget, "Missing Library",
            "openpyxl is not installed.\n\nRun:  pip install openpyxl"); return
    # If no rows passed, fetch all from DB
    if rows is None:
        conn = sqlite3.connect(DB_PATH); c = conn.cursor()
        c.execute("""
            SELECT
                i.invoice_no, i.date,
                COALESCE(p.id,'') AS patient_id,
                i.patient_name, i.patient_phone, i.net_amount
            FROM invoices i
            LEFT JOIN patients p
                ON TRIM(LOWER(i.patient_phone)) = TRIM(LOWER(p.mobile))
               AND TRIM(LOWER(i.patient_name))  = TRIM(LOWER(p.name))
            ORDER BY i.id
        """)
        rows_data = c.fetchall(); conn.close()
    else:
        # rows are (id, invoice_no, date, patient_id, patient_name, phone, net_amount)
        # Reverse so oldest invoice is Sr.1 at top, newest at bottom (chronological order)
        rows_data = [(r[1], r[2], r[3], r[4], r[5], r[6]) for r in reversed(rows)]

    path, _ = QFileDialog.getSaveFileName(
        parent_widget, "Export Invoices to Excel",
        f"Invoices_{datetime.now().strftime('%Y%m%d_%H%M')}.xlsx",
        "Excel Files (*.xlsx)")
    if not path: return
    wb = Workbook(); ws = wb.active; ws.title = "Invoice History"
    ws.freeze_panes = "A2"
    ws.append(["Sr. No.", "Invoice ID", "Date", "Patient ID", "Patient Name", "Mobile", "Net Amount (\u20b9)"])
    data_row_nums = []
    for sr, row in enumerate(rows_data, 1):
        ws.append([sr] + list(row)); data_row_nums.append(ws.max_row)
    amt_col = 7; amt_letter = get_column_letter(amt_col)  # now col 7
    if data_row_nums:
        sum_row = max(data_row_nums) + 1
        ws.cell(sum_row, 1).value = "NET TOTAL"
        ws.cell(sum_row, amt_col).value = f"=SUM({amt_letter}2:{amt_letter}{max(data_row_nums)})"
        ws.cell(sum_row, amt_col).number_format = '#,##0.00'
    for r in data_row_nums:
        ws.cell(r, amt_col).number_format = '#,##0.00'
    _xl_style(ws, 1, data_row_nums, sum_col=amt_col)
    try:
        wb.save(path)
        QMessageBox.information(parent_widget, "\u2714  Exported",
            f"{len(rows_data)} record(s) exported!\n\n{path}")
        if platform.system() == "Windows": os.startfile(path)
    except Exception as e:
        QMessageBox.critical(parent_widget, "Export Error", str(e))

def export_patients_excel(parent_widget):
    """Export all patient records to Excel with all fields + total count row."""
    try:
        from openpyxl import Workbook
    except ImportError:
        QMessageBox.critical(parent_widget, "Missing Library",
            "openpyxl is not installed.\n\nRun:  pip install openpyxl"); return
    path, _ = QFileDialog.getSaveFileName(
        parent_widget, "Export Patient Data to Excel",
        f"Patients_{datetime.now().strftime('%Y%m%d_%H%M')}.xlsx",
        "Excel Files (*.xlsx)")
    if not path: return
    rows = all_patients()
    wb = Workbook(); ws = wb.active; ws.title = "Patient Database"
    ws.freeze_panes = "A2"
    ws.append(["Patient ID", "Name", "Age", "Gender", "Mobile", "Email", "Address"])
    data_row_nums = []
    for row in rows:
        ws.append(list(row)); data_row_nums.append(ws.max_row)
    if data_row_nums:
        sum_row = max(data_row_nums) + 1
        ws.cell(sum_row, 1).value = "TOTAL PATIENTS"
        ws.cell(sum_row, 2).value = len(rows)
    _xl_style(ws, 1, data_row_nums, sum_col=1)
    try:
        wb.save(path)
        QMessageBox.information(parent_widget, "\u2714  Exported", f"Patient data exported!\n\n{path}")
        if platform.system() == "Windows": os.startfile(path)
    except Exception as e:
        QMessageBox.critical(parent_widget, "Export Error", str(e))


def num_words(n):
    ones=['','One','Two','Three','Four','Five','Six','Seven','Eight','Nine','Ten',
          'Eleven','Twelve','Thirteen','Fourteen','Fifteen','Sixteen','Seventeen','Eighteen','Nineteen']
    tens_=['','','Twenty','Thirty','Forty','Fifty','Sixty','Seventy','Eighty','Ninety']
    def h(n):
        if n<20: return ones[n]
        elif n<100: return tens_[n//10]+(' '+ones[n%10] if n%10 else '')
        elif n<1000: return ones[n//100]+' Hundred'+(' '+h(n%100) if n%100 else '')
        elif n<100000: return h(n//1000)+' Thousand'+(' '+h(n%1000) if n%1000 else '')
        else: return h(n//100000)+' Lakh'+(' '+h(n%100000) if n%100000 else '')
    n=int(n); return 'Zero' if n==0 else h(n)+' Only'

