def _inv_body(d, shop, label=""):
    MIN_ROWS = 4  # always show at least 5 item rows
    items = d.get("items", [])
    rows = ""
    for i, item in enumerate(items, 1):
        pack  = item.get('pack_size','').strip()
        if pack.lower() in ['1 visit', '1 session', 'visit', 'session', '1 pack']:
            pack = ''
        pname = item.get('product','')
        pcell = f"{pname} <span style='color:#888;font-weight:400'>- {pack}</span>" if pack else pname
        try: qd = int(item['qty']) if float(item['qty'])==int(float(item['qty'])) else item['qty']
        except: qd = item.get('qty','')
        qty   = float(item.get('qty', 0))
        rate  = float(item.get('rate', 0))
        total_amt = qty * rate
        rows += f"""<tr>
          <td class=c>{i}</td><td class=l>{pcell}</td>
          <td class=r>&#8377;{rate:.2f}</td>
          <td class=c>{qd}</td>
          <td class=r>&#8377;{total_amt:.2f}</td>
        </tr>"""
    # Pad with empty rows to ensure minimum MIN_ROWS height
    blank_row = "<tr style='height:20px'><td>&nbsp;</td><td></td><td></td><td></td><td></td></tr>"
    for _ in range(max(0, MIN_ROWS - len(items))):
        rows += blank_row
    net = d.get('net_amount', 0)
    s = shop

    label_html = ""
    if label:
        icon = "📋" if "Admin" in label else "🧾"
        label_html = f'<div class="copy-label"><span>{icon}</span> {label.upper()}</div>'

    # Build address lines
    addr_parts = [s.get('address1',''), s.get('address2',''), s.get('address3','')]
    addr_html = '<br>'.join(p for p in addr_parts if p.strip())

    # Patient details with normalization & auto-title
    raw_gen = d.get('patient_gender','').strip().lower()
    gender = d.get('patient_gender','').strip()
    title = ""
    if raw_gen in ['m', 'male', 'boy']:
        gender = "Male"; title = "Mr. "
    elif raw_gen in ['f', 'female', 'girl']:
        gender = "Female"; title = "Ms. "
    
    pname = d.get('patient_name','—').strip()
    if title and not pname.lower().startswith(title.lower()):
        pname = title + pname

    page = d.get('patient_age','').strip()
    pph = d.get('patient_phone','').strip()
    if pph and not pph.startswith('+'):
        pph = "+91 " + pph
        
    pemail = d.get('patient_email','').strip()
    paddr = d.get('patient_address','').strip()
    
    bits = []
    if page:   bits.append(f"{page} yrs")
    if gender: bits.append(gender)
    if pph:    bits.append(pph)
    if pemail: bits.append(pemail)
    
    # Header line: Name followed by other bits
    pat_html_main = f"<span class='pat-name-big'>{pname}</span>"
    if bits:
        pat_html_main += ", " + ", ".join(f"<span class='pat-item'>{b}</span>" for b in bits)
        
    if paddr:
        pat_html_main += f", <span class='pat-item'><b>Address:</b> {paddr}</span>"
    
    pat_items = [pat_html_main]

    # Payment section
    # Payment section details
    pm          = d.get('payment_mode', 'Cash')
    
    # Defensive float conversion for DB nulls/missing keys
    def fv(k, default=0.0):
        val = d.get(k)
        if val is None: return float(default)
        try: return float(val)
        except: return float(default)

    net     = fv('net_amount')
    paid    = fv('paid_amount', 0)

    # Discount row — only show if discount > 0
    dp = d.get('discount_pct', 0)
    da = d.get('discount_amt', 0)
    disc_row = ""
    if dp and dp > 0:
        disc_row = f'<div class="trow disc"><span>Discount ({dp:.1f}%)</span><span>&#8722;&#8377;{da:.2f}</span></div>'

    logo = s.get('logo_path','')
    if logo and logo.startswith('data:'):
        # Embedded base64 data URI — use directly
        logo_html = f'<img src="{logo}">'
    elif logo and os.path.exists(logo):
        import base64 as _b64
        try:
            with open(logo, "rb") as f:
                _data = _b64.b64encode(f.read()).decode('utf-8')
            ext = os.path.splitext(logo)[1].lower().strip('.')
            if ext == 'jpg': ext = 'jpeg'
            logo_html = f'<img src="data:image/{ext};base64,{_data}">'
        except Exception:
            logo_html = '<div style="font-size:24px; color:#ddd; margin-top:10px">&#10043;</div>'
    else:
        logo_html = '<div style="font-size:24px; color:#ddd; margin-top:10px">&#10043;</div>'

    # Patient ID lookup
    pid_val = d.get('patient_id','')
    if not pid_val:
        # try lookup via raw name+phone from 'd' (avoid titles/prefixes added for display)
        raw_name  = d.get('patient_name','').strip()
        raw_phone = d.get('patient_phone','').strip()
        matches = patients_by_mobile(raw_phone)
        
        def norm(n):
            n = n.lower().strip()
            for t in ["mr. ", "ms. ", "mrs. ", "dr. "]:
                if n.startswith(t): n = n[len(t):].strip()
            return n
            
        target = norm(raw_name)
        for m in matches:
            if norm(m['name']) == target:
                pid_val = m['id']; break

    # Dynamic Receipt Number based on Invoice Number: TP/FY/001 -> RCT001
    inv_no = d.get('invoice_no', '—')
    try:
        if "/" in inv_no:
            seq = inv_no.split("/")[-1]
            receipt_no = f"RCT{seq}"
        else:
            # Fallback for old IN-XXX format if any
            import re
            m = re.search(r'\d+', inv_no)
            receipt_no = f"RCT{m.group()}" if m else f"RCT{inv_no}"
    except:
        receipt_no = f"RCT{inv_no}"

    return f"""
  {label_html}
  <div class="hdr">
    <div class="hdr-left">
      <div class="shop-name">{s.get('shop_name','')}</div>
      <div class="shop-tag">{s.get('store_tag','')}</div>
      <div class="shop-addr-line">{addr_html}</div>
    </div>
    <div class="hdr-right">
      <div class="dr-name">{s.get('dr_name','')}</div>
      <div class="info-line">Regd. No.: {s.get('regd_no','')}</div>
      <div class="info-line">Mob.: {s.get('phone','')}</div>
      <div class="info-line">{s.get('website','')}</div>
    </div>
  </div>

  <div class="inv-meta">
    <div>
      <div class="lbl">Invoice Number</div>
      <div class="val">{inv_no}</div>
    </div>
    <div>
      <div class="lbl">Patient ID</div>
      <div class="val">{pid_val or '—'}</div>
    </div>
    <div>
      <div class="lbl">Date</div>
      <div class="val">{d.get('date','—')}</div>
    </div>
  </div>

  <div class="pat-box">
    <div class="pat-row">{''.join(pat_items)}</div>
  </div>

  <table>
    <thead><tr>
      <th style="width:22px">#</th>
      <th class=l>Description</th>
      <th style="width:70px" class=r>Charges (&#8377;)</th>
      <th style="width:36px">Unit</th>
      <th style="width:80px" class=r>Total (&#8377;)</th>
    </tr></thead>
    <tbody>{rows}</tbody>
  </table>

  <div class="bottom-row top">
    <div class="left">
      <div class="remarks-box">
        <b>REMARKS:</b><br>{d.get('remarks','') or ''}
      </div>
    </div>
    <div class="right">
      <div class="totals">
        <div class="trow"><span>Sub Total</span><span>&#8377;{d.get('subtotal',0):.2f}</span></div>
        {disc_row}
        <div class="trow net"><span>NET AMOUNT</span><span>&#8377;{net:.2f}</span></div>
      </div>
    </div>
  </div>

  <div class="bottom-row">
    <div class="left">
      <div class="pay-info">
        <table>
          <thead><tr>
            <th>Receipt No.</th><th>Date</th><th>Mode</th><th>Amount Received (&#8377;)</th>
          </tr></thead>
          <tbody>
            <tr>
              <td>{receipt_no}</td>
              <td>{d.get('date','—')}</td>
              <td>{pm}</td>
              <td>&#8377;{paid:.2f}</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
    <div class="right" style="text-align:center">
      <div class="sig">Authorised Sign.</div>
    </div>
  </div>
</div>"""

def build_preview_html(d, shop):
    return f"""<html><head><meta charset='utf-8'>{INVOICE_CSS}
    <style>
    body{{background:#d8dae8;margin:0;padding:20px}}
    .page{{background:#fff;max-width:750px;margin:0 auto;
           box-shadow:0 6px 30px rgba(0,0,0,0.22);border-radius:5px}}
    </style>
    </head><body><div class="page">{_inv_body(d,shop)}</div></body></html>"""

def build_single_html(d, shop, for_print=False):
    """A4 portrait: invoice on top half, blank white bottom half.
    A dashed CUT HERE line separates the two halves.
    """
    page_css = """
    @page{size:A4 portrait;margin:0}
    html,body{margin:0;padding:0;background:#fff;color:#000;width:210mm}
    .invoice-half{
        width:210mm;
        max-height:148.5mm;
        padding:3mm 3mm 4mm 3mm;
        box-sizing:border-box;
        overflow:hidden;
    }
    .cut-line{
        width:210mm;height:0;
        border-top:1.5px dashed #bbb;
        text-align:center;
        line-height:0;
        margin:0;
        position:relative;
    }
    .cut-line span{
        background:#fff;
        padding:0 8px;
        font-size:8px;
        color:#bbb;
        letter-spacing:3px;
        position:relative;
        top:-6px;
    }
    .blank-half{
        width:210mm;height:148mm;
        background:#fff;
        display:block;
    }"""
    return f"""<html><head><meta charset='utf-8'>{INVOICE_CSS}
    <style>
    {page_css}
    /* Patient details row in 1 line */
    body, td, .pat-item, .remarks-box {{color:#000 !important}}
    th, .trow.net {{color:#fff !important}}
    .shop-addr-line, .hdr-right .info-line {{color:#111 !important}}
    .shop-name{{font-size:28px;color:#000}}
    .shop-addr-line{{font-size:14px;margin-top:1px;line-height:1.2;color:#111}}
    .shop-tag{{font-size:13px;color:#333}}
    .hdr{{padding-bottom:2px;margin-bottom:2px}}
    .hdr-center img{{max-height:65px;max-width:110px}}
    .dr-name{{font-size:28px;color:#000}}
    .hdr-right .info-line{{font-size:14px;line-height:1.3;color:#111}}
    .inv-meta{{padding:2px 5px;margin-bottom:2px}}
    .inv-meta .val{{font-size:14px;color:#000}}
    .inv-meta .lbl{{font-size:11px}}
    .pat-box{{padding:2px 5px;margin-bottom:2px}}
    .pat-box .lbl{{font-size:11px}}
    .pat-name-big{{font-size:18px;color:#000}}
    .pat-item{{font-size:14px;color:#000}}
    .pat-item b{{color:#000}}
    th{{font-size:12px;padding:3px 3px;color:#fff !important}}
    td{{font-size:14px;padding:3px 3px;color:#000}}
    td.r{{font-weight:800}}
    .trow{{font-size:14px;padding:3px 12px;color:#000;font-weight:600}}
    .trow.net{{font-size:16px;padding:4px 12px;color:#fff !important;font-weight:900}}
    .trow.received{{font-size:14px;font-weight:800}}
    .trow.due{{font-size:14.5px;font-weight:800}}
    .footer{{font-size:11px;margin-top:3px;padding-top:2px}}
    .sig{{margin-top:70px;min-width:180px;font-size:13px;color:#000;text-align:center}}
    .copy-label{{display:none}}
    .pay-info td{{font-size:13px;padding:3px 10px;color:#000;text-align:center}}
    .pay-info th{{font-size:11px;padding:3px 10px;color:#fff !important}}
    .remarks-box{{font-size:13.5px;color:#000;padding:0 10px 2px 10px;white-space:pre-line}}
    .bottom-row{{display:flex;gap:12px;align-items:flex-start;margin-top:0}}
    .bottom-row.top{{align-items:flex-start}}
    .bottom-row .left{{flex:1}}
    .bottom-row .right{{width:275px}}
    .totals{{width:100%}}
    </style>
    </head><body>
    <div class="invoice-half">
    {_inv_body(d,shop,'')}
    </div>

    <div class="blank-half"></div>
    </body></html>"""

