class PreviewDialog(QDialog):
    def __init__(self, html, parent=None):
        super().__init__(parent)
        self.setWindowTitle("Invoice Preview")
        self.setWindowFlags(Qt.WindowType.Dialog |
                            Qt.WindowType.WindowMaximizeButtonHint |
                            Qt.WindowType.WindowCloseButtonHint)
        self.resize(820, 920)
        self.setStyleSheet(f"background:{BG};")
        l = QVBoxLayout(self); l.setContentsMargins(0,0,0,0); l.setSpacing(0)

        bar = QFrame(); bar.setObjectName("topbar"); bar.setFixedHeight(60)
        bl = QHBoxLayout(bar); bl.setContentsMargins(18,0,18,0); bl.setSpacing(10)
        icon = QLabel("◈"); icon.setStyleSheet(f"color:{ACCENT};font-size:18px;background:transparent")
        ttl  = QLabel("Invoice Preview")
        ttl.setStyleSheet(f"color:{TP};font-weight:700;font-size:16px;background:transparent")
        hint = QLabel("Single copy preview  ·  PDF export has both copies")
        hint.setStyleSheet(f"color:{TM};font-size:13px;background:transparent")
        btn_close = QPushButton("✕  Close"); btn_close.setFixedWidth(100); btn_close.setFixedHeight(34)
        btn_close.clicked.connect(self.close)
        bl.addWidget(icon); bl.addSpacing(6); bl.addWidget(ttl); bl.addStretch()
        bl.addWidget(hint); bl.addSpacing(14); bl.addWidget(btn_close)
        l.addWidget(bar)

        self.web = QWebEngineView()
        self.web.setHtml(html)
        l.addWidget(self.web)

# ═══════════════════════════════════════
#  BILLING TAB
# ═══════════════════════════════════════
class BillingTab(QWidget):
    invoice_saved = pyqtSignal()
    patient_db_updated = pyqtSignal()  # emitted after invoice save to refresh patients tab

    def __init__(self, parent=None):
        super().__init__(parent)
        self.shop = get_shop()
        self.invoice_no = next_invoice_no()
        self.current_invoice_id = None  # To track if we are editing an existing invoice
        self.current_patient_id = None
        self._current_data = {}
        self._build_ui()
        self._reset()

    def _build_ui(self):
        sc = UI_SCALE
        f18 = max(12, int(18 * sc))
        f14 = max(10, int(14 * sc))
        f13 = max(9,  int(13 * sc))
        f11 = max(8,  int(11 * sc))
        f15 = max(10, int(15 * sc))
        f22 = max(14, int(22 * sc))
        f12 = max(9,  int(12 * sc))
        p8  = max(4,  int(8  * sc))
        p12 = max(6,  int(12 * sc))
        root = QVBoxLayout(self)
        root.setContentsMargins(16, 10, 16, 10)
        root.setSpacing(8)

        # ── Title row + action buttons (all in ONE row) ─────────
        title_row = QHBoxLayout(); title_row.setSpacing(8)
        icon = QLabel("◈")
        icon.setStyleSheet(f"color:{ACCENT};font-size:{f18}px;background:transparent;font-weight:900")
        title = QLabel("New Invoice")
        title.setStyleSheet(f"color:{TP};font-size:{f18}px;font-weight:800;background:transparent")
        self.inv_badge = QLabel("R-000001")
        self.inv_badge.setStyleSheet(
            f"color:{ACCENT};font-size:{f13}px;font-weight:800;"
            f"background:{ACCENT_D};border:1px solid {ACCENT}55;"
            f"border-radius:6px;padding:3px 12px")
        title_row.addWidget(icon); title_row.addSpacing(4)
        title_row.addWidget(title); title_row.addSpacing(8)
        title_row.addWidget(self.inv_badge); title_row.addStretch()

        btn_new     = QPushButton("＋ New")
        btn_preview = QPushButton("◉ Preview");   btn_preview.setObjectName("accent")
        btn_save    = QPushButton("✔ Save");       btn_save.setObjectName("green")
        btn_pdf     = QPushButton("⬇ PDF");        btn_pdf.setObjectName("yellow")
        btn_print   = QPushButton("⎙ Print")
        for b in [btn_new,btn_preview,btn_save,btn_pdf,btn_print]:
            b.setFixedHeight(32)
        btn_new.setToolTip("Clear and start a new invoice")
        btn_pdf.setToolTip("Export Admin & Customer copies as one PDF")
        btn_new.clicked.connect(self._reset)
        btn_preview.clicked.connect(self._preview)
        btn_save.clicked.connect(self._save)
        btn_pdf.clicked.connect(self._export_pdf)
        btn_print.clicked.connect(self._print)
        for b in [btn_new, btn_preview, btn_save, btn_pdf, btn_print]:
            title_row.addWidget(b)
        root.addLayout(title_row)

        # ── Patient info — single compact horizontal card ──────
        pcard = QFrame(); pcard.setObjectName("card")
        pg = QHBoxLayout(pcard); pg.setContentsMargins(14,9,14,9); pg.setSpacing(14)

        def _lfield(label, placeholder, fixed_w=None):
            w = QWidget(); w.setStyleSheet("background:transparent")
            vl = QVBoxLayout(w); vl.setContentsMargins(0,0,0,0); vl.setSpacing(2)
            lbl = QLabel(label.upper())
            lbl.setStyleSheet(f"color:{TM};font-size:{f11}px;font-weight:700;letter-spacing:1px;background:transparent")
            inp = QLineEdit(); inp.setPlaceholderText(placeholder)
            if fixed_w: inp.setFixedWidth(fixed_w)
            vl.addWidget(lbl); vl.addWidget(inp)
            return w, inp

        w0, self.pid_edit      = _lfield("Patient ID",   "TPRC01",           110)
        w1, self.patient_edit  = _lfield("Patient Name", "Patient / Customer name")
        w2, self.age_edit      = _lfield("Age",          "Age (yrs)",        95)
        w3, self.gender_edit   = _lfield("Gender",       "M / F / Other",   120)
        w4, self.phone_edit    = _lfield("Mobile",       "Phone number",    165)
        w5, self.email_edit    = _lfield("Email",        "Email (opt.)",    200)
        w6, self.date_edit     = _lfield("Date",         "DD-MM-YYYY",      130)
        self._patient_autofill_lock = False  # prevent re-entrant signals

        # ── Patient Name autocomplete — shows "Name (mobile)" for disambiguation ──
        self._name_completer = QCompleter(all_patient_name_labels(), self.patient_edit)
        self._name_completer.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        self._name_completer.setFilterMode(Qt.MatchFlag.MatchContains)
        self._name_completer.setCompletionMode(QCompleter.CompletionMode.PopupCompletion)
        self.patient_edit.setCompleter(self._name_completer)
        self._name_completer.activated.connect(self._on_patient_name_selected)
        self.patient_edit.textChanged.connect(self._on_patient_name_typed)

        # ── Patient ID autocomplete ──────────────────────────────────
        self._pid_completer = QCompleter(all_patient_ids(), self.pid_edit)
        self._pid_completer.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        self._pid_completer.setFilterMode(Qt.MatchFlag.MatchContains)
        self.pid_edit.setCompleter(self._pid_completer)
        self._pid_completer.activated.connect(self._on_pid_selected)
        self.pid_edit.editingFinished.connect(lambda: self._on_pid_selected(self.pid_edit.text()))

        # ── Mobile lookup search + Completer ──────────────────────────
        self._mobile_completer = QCompleter(all_patient_mobile_labels(), self.phone_edit)
        self._mobile_completer.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        self._mobile_completer.setFilterMode(Qt.MatchFlag.MatchContains)
        self._mobile_completer.setCompletionMode(QCompleter.CompletionMode.PopupCompletion)
        self.phone_edit.setCompleter(self._mobile_completer)
        self._mobile_completer.activated.connect(self._on_mobile_selected)
        self.phone_edit.textChanged.connect(self._on_mobile_typed)
        self.phone_edit.editingFinished.connect(self._on_mobile_entered)

        pg.addWidget(w0); pg.addWidget(w1, 1)  # stretch — takes all remaining space
        pg.addWidget(w2); pg.addWidget(w3)
        pg.addWidget(w4); pg.addWidget(w5); pg.addWidget(w6)

        # Address + Remarks row
        pcard2 = QFrame(); pcard2.setObjectName("card")
        pg2 = QHBoxLayout(pcard2); pg2.setContentsMargins(14,6,14,6); pg2.setSpacing(14)
        wa, self.addr_edit = _lfield("Patient Address", "Full address of patient")
        
        wr = QWidget(); wr.setStyleSheet("background:transparent")
        vlr = QVBoxLayout(wr); vlr.setContentsMargins(0,0,0,0); vlr.setSpacing(2)
        rlbl = QLabel("REMARKS / NOTES")
        rlbl.setStyleSheet(f"color:{TM};font-size:{f11}px;font-weight:700;letter-spacing:1px;background:transparent")
        from PyQt6.QtWidgets import QTextEdit
        self.remarks_edit = QTextEdit()
        self.remarks_edit.setPlaceholderText("Any additional clinical notes or remarks")
        self.remarks_edit.setFixedHeight(int(40 * sc))
        self.remarks_edit.setStyleSheet(f"font-size:{f13}px;font-weight:700;color:{TP};padding:{p8}px {p12}px;border:1px solid {BORDER};border-radius:8px;background:{BG_INPUT};")
        vlr.addWidget(rlbl); vlr.addWidget(self.remarks_edit)

        pg2.addWidget(wa, 2); pg2.addWidget(wr, 1) # Remarks takes less space
        root.addWidget(pcard)
        root.addWidget(pcard2)

        # ── Items mini-header ──────────────────────────────────
        items_hdr = QHBoxLayout(); items_hdr.setSpacing(8)
        items_lbl = QLabel("BILL ITEMS")
        items_lbl.setStyleSheet(
            f"color:{TM};font-size:{f14}px;font-weight:700;letter-spacing:1.5px;background:transparent")
        items_hdr.addWidget(items_lbl); items_hdr.addStretch()
        btn_add_row = QPushButton("＋  Add Item")
        btn_del_row = QPushButton("✕  Remove"); btn_del_row.setObjectName("red")
        btn_add_row.setFixedHeight(30); btn_del_row.setFixedHeight(30)
        btn_add_row.clicked.connect(lambda: self._add_row())
        btn_del_row.clicked.connect(self._del_row)
        items_hdr.addWidget(btn_add_row); items_hdr.addWidget(btn_del_row)
        root.addLayout(items_hdr)

        # ── Items table — STRETCH to fill all remaining space ──
        self.table = QTableWidget()
        self.table.setColumnCount(5)
        self.table.setHorizontalHeaderLabels(["#","Description","Pack / Unit","Rate (₹)","Qty"])
        hh = self.table.horizontalHeader()
        hh.setSectionResizeMode(1, QHeaderView.ResizeMode.Stretch)
        for col in [0,2,3,4]: hh.setSectionResizeMode(col, QHeaderView.ResizeMode.Fixed)
        self.table.setColumnWidth(0,40); self.table.setColumnWidth(2,130)
        self.table.setColumnWidth(3,125); self.table.setColumnWidth(4,80)
        self.table.setAlternatingRowColors(True)
        self.table.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
        self.table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
        self.table.itemChanged.connect(lambda _: self._recalc())
        self.table.verticalHeader().setVisible(False)
        root.addWidget(self.table, 1)   # ← stretch factor keeps table large

        # ── Totals strip + Net amount ──────────────────────────
        bot = QHBoxLayout(); bot.setSpacing(10)

        tcard = QFrame(); tcard.setObjectName("card")
        tg = QHBoxLayout(tcard); tg.setContentsMargins(max(8,int(14*sc)),max(4,int(8*sc)),max(8,int(14*sc)),max(4,int(8*sc))); tg.setSpacing(max(6,int(12*sc)))

        def _tfield(label, fixed_w=125):
            w = QWidget(); w.setStyleSheet("background:transparent")
            vl = QVBoxLayout(w); vl.setContentsMargins(0,0,0,0); vl.setSpacing(3)
            lbl = QLabel(label.upper())
            lbl.setStyleSheet(f"color:{TP};font-size:{f11}px;font-weight:800;letter-spacing:0.8px;background:transparent")
            fw = max(70, int(fixed_w * sc))
            f = QLineEdit(); f.setReadOnly(True); f.setFixedWidth(fw)
            f.setStyleSheet(f"font-size:{f13}px;font-weight:700;color:{TP};padding:{p8}px {p12}px;")
            vl.addWidget(lbl); vl.addWidget(f)
            return w, f

        def _efield(label, placeholder="", fixed_w=120):
            w = QWidget(); w.setStyleSheet("background:transparent")
            vl = QVBoxLayout(w); vl.setContentsMargins(0,0,0,0); vl.setSpacing(3)
            lbl = QLabel(label.upper())
            lbl.setStyleSheet(f"color:{TP};font-size:{f11}px;font-weight:800;letter-spacing:0.8px;background:transparent")
            fw = max(70, int(fixed_w * sc))
            f = QLineEdit(); f.setPlaceholderText(placeholder); f.setFixedWidth(fw)
            f.setStyleSheet(f"font-size:{f13}px;font-weight:700;color:{TP};padding:{p8}px {p12}px;")
            vl.addWidget(lbl); vl.addWidget(f)
            return w, f

        w_sub, self.subtotal_f = _tfield("Subtotal", 130)

        wd = QWidget(); wd.setStyleSheet("background:transparent")
        vld = QVBoxLayout(wd); vld.setContentsMargins(0,0,0,0); vld.setSpacing(2)
        lbl_d = QLabel("DISCOUNT %")
        lbl_d.setStyleSheet(f"color:{TP};font-size:{f11}px;font-weight:800;letter-spacing:0.8px;background:transparent")
        self.disc_edit = QLineEdit("0"); self.disc_edit.setFixedWidth(max(55, int(85 * sc)))
        self.disc_edit.setStyleSheet(f"font-size:{f13}px;font-weight:700;color:{TP};padding:{p8}px {p12}px;")
        self.disc_edit.textChanged.connect(self._recalc)
        vld.addWidget(lbl_d); vld.addWidget(self.disc_edit)

        w_da, self.disc_amt_f = _tfield("Disc. Amt", 115)

        # Payment mode
        wpm = QWidget(); wpm.setStyleSheet("background:transparent")
        vlpm = QVBoxLayout(wpm); vlpm.setContentsMargins(0,0,0,0); vlpm.setSpacing(2)
        lbl_pm = QLabel("PAYMENT MODE")
        lbl_pm.setStyleSheet(f"color:{TP};font-size:{f11}px;font-weight:800;letter-spacing:0.8px;background:transparent")
        from PyQt6.QtWidgets import QComboBox
        self.pay_mode = QComboBox(); self.pay_mode.addItems(["Cash","UPI","Cash + UPI","Other"])
        self.pay_mode.setFixedWidth(max(100, int(145 * sc)))
        self.pay_mode.setStyleSheet(f"""
            QComboBox {{
                font-size:{f13}px;font-weight:700;color:{TP};
                padding:{p8}px {p12}px;border:1px solid {BORDER};
                border-radius:8px;background:{BG_INPUT};
            }}
            QComboBox:focus {{ border:1.5px solid {ACCENT}; }}
            QComboBox::drop-down {{ border:none;width:24px; }}
            QComboBox QAbstractItemView {{
                font-size:{f13}px;font-weight:700;color:{TP};
                background:{BG_CARD};border:1.5px solid {ACCENT};
                selection-background-color:{ACCENT};selection-color:white;
            }}
        """)
        vlpm.addWidget(lbl_pm); vlpm.addWidget(self.pay_mode)

        w_payab, self.payable_f    = _tfield("Payable Amount", 140); self.payable_f.setStyleSheet(f"font-size:{f14}px;font-weight:900;color:{ACCENT};padding:{p8}px {p12}px;background:{BG_HOVER}")
        w_paid, self.paid_edit     = _efield("Paid Amt",      "0.00", 120)
        self.paid_edit.textChanged.connect(self._recalc_payment)
        for w in [w_sub, wd, w_da, wpm, w_payab, w_paid]:
            tg.addWidget(w)
        bot.addWidget(tcard, 3)

        netcard = QFrame(); netcard.setObjectName("netcard")
        nl = QVBoxLayout(netcard); nl.setContentsMargins(12,6,12,6); nl.setSpacing(0)
        net_lbl = QLabel("NET AMOUNT")
        net_lbl.setStyleSheet(f"font-size:{f12}px;font-weight:700;color:{GREEN};"
                               f"letter-spacing:2px;background:transparent")
        net_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.net_display = QLabel("₹ 0.00")
        self.net_display.setStyleSheet(
            f"font-size:{f22}px;font-weight:900;color:{GREEN};background:transparent")
        self.net_display.setAlignment(Qt.AlignmentFlag.AlignCenter)

        nl.addWidget(net_lbl); nl.addWidget(self.net_display)
        bot.addWidget(netcard, 1)
        root.addLayout(bot)

    # ── Helpers ──────────────────────────────────────────────
    def _add_row(self, data=None):
        self.table.blockSignals(True)
        r = self.table.rowCount(); self.table.insertRow(r)

        sr = QTableWidgetItem(str(r+1))
        sr.setFlags(Qt.ItemFlag.ItemIsEnabled)
        sr.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
        sr.setForeground(QColor(TM))
        self.table.setItem(r, 0, sr)

        prod_edit = QLineEdit()
        prod_edit.setStyleSheet(
            f"background:{BG_INPUT};border:none;color:{TP};"
            f"font-size:14px;padding:5px 10px;border-radius:0")
        names = [p[1] for p in get_all_products()]
        comp = QCompleter(names, prod_edit)
        comp.setCaseSensitivity(Qt.CaseSensitivity.CaseInsensitive)
        comp.setFilterMode(Qt.MatchFlag.MatchContains)
        prod_edit.setCompleter(comp)

        def fill(name, row=r):
            p = get_product_by_name(name)
            if p:
                self.table.blockSignals(True)
                self._sc(row,2,p.get("pack_size",""))
                self._sc(row,3,str(p.get("price",0)))
                self._sc(row,4,"1")
                self.table.blockSignals(False)
                self._recalc()

        prod_edit.textChanged.connect(lambda t: fill(t) if get_product_by_name(t) else None)
        comp.activated.connect(fill)
        self.table.setCellWidget(r, 1, prod_edit)

        for c, v in enumerate(["","0","1"], 2):
            it = QTableWidgetItem(v); it.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
            self.table.setItem(r, c, it)

        if data:
            prod_edit.setText(data.get("product",""))
            self._sc(r,2,data.get("pack_size",""))
            self._sc(r,3,str(data.get("rate",0)))
            self._sc(r,4,str(data.get("qty",1)))

        self.table.setRowHeight(r,45); self.table.blockSignals(False); self._recalc()

    def _sc(self, r, c, val):
        it = self.table.item(r, c)
        if it: it.setText(str(val))
        else:
            it = QTableWidgetItem(str(val)); it.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
            self.table.setItem(r, c, it)

    def _del_row(self):
        row = self.table.currentRow()
        if row >= 0:
            self.table.removeRow(row)
            for i in range(self.table.rowCount()):
                self.table.item(i,0).setText(str(i+1))
            self._recalc()

    def _collect(self):
        self.table.blockSignals(True)
        items=[]; sub=0
        for r in range(self.table.rowCount()):
            w = self.table.cellWidget(r,1); pname = w.text() if w else ""
            def cell(c, row=r):
                it = self.table.item(row,c); return it.text() if it else ""
            try: rate=float(cell(3))
            except: rate=0
            try: qty=float(cell(4))
            except: qty=0
            base=qty*rate
            sub+=base
            items.append({"product":pname,"pack_size":cell(2),
                          "qty":qty,"rate":rate,"amount":base})
        try: dp=max(0.0,min(100.0,float(self.disc_edit.text())))
        except: dp=0.0
        da=sub*dp/100; after=sub-da
        net_raw=after; netr=round(net_raw); ro=netr-net_raw

        payable = float(netr)

        try: paid_str = self.paid_edit.text().strip()
        except: paid_str = ""
        
        if not paid_str:
             paid = 0.0 # Don't default to netr anymore if using payable logic
        else:
             try: paid = float(paid_str)
             except: paid = 0.0

        self.table.blockSignals(False)
        return {
            "invoice_no":      self.invoice_no,
            "date":            self.date_edit.text(),
            "patient_id":      self.current_patient_id,
            "patient_name":    self.patient_edit.text(),
            "patient_age":     self.age_edit.text(),
            "patient_gender":  self.gender_edit.text(),
            "patient_phone":   self.phone_edit.text(),
            "patient_email":   self.email_edit.text(),
            "patient_address": self.addr_edit.text(),
            "doctor":          self.shop.get("dr_name",""),
            "items": items,
            "subtotal":        round(sub,2), "discount_pct":dp,
            "discount_amt":    round(da,2),  "round_off":round(ro,2),
            "net_amount":      float(netr),
            "payment_mode":    self.pay_mode.currentText(),
            "paid_amount":     round(paid,2),
            "payable_amt":     round(payable,2),
            "remarks":         self.remarks_edit.toPlainText(),
        }

    def _recalc(self):
        d = self._collect(); self._current_data = d

        self.subtotal_f.setText(f"{d['subtotal']:.2f}")
        self.disc_amt_f.setText(f"{d['discount_amt']:.2f}")
        self.payable_f.setText(f"{d['payable_amt']:.2f}")
        self.net_display.setText(f"₹ {d['net_amount']:.2f}")

    def _recalc_payment(self):
        self._recalc()

    def _reset(self):
        self.table.blockSignals(True); self.table.setRowCount(0); self.table.blockSignals(False)
        self.pid_edit.clear(); self.patient_edit.clear(); self.age_edit.clear(); self.gender_edit.clear()
        self.phone_edit.clear(); self.email_edit.clear(); self.addr_edit.clear()
        self.remarks_edit.clear()
        self.current_invoice_id = None
        self.current_patient_id = None
        self.invoice_no = next_invoice_no()
        self.inv_badge.setText(self.invoice_no)
        self.date_edit.setText(datetime.now().strftime("%d-%m-%Y"))
        self.disc_edit.setText("0")
        self.paid_edit.clear()
        self._add_row(); self._recalc()
        # Refresh completer lists
        self._name_completer.model().setStringList(all_patient_name_labels())
        self._mobile_completer.model().setStringList(all_patient_mobile_labels())
        self._pid_completer.model().setStringList(all_patient_ids())

    # ── Patient autofill helpers ─────────────────────────────────────
    def _fill_patient_fields(self, p):
        """Fill all patient detail fields from a patient dict."""
        self._patient_autofill_lock = True
        self.current_patient_id = p.get("id")
        self.pid_edit.setText(self.current_patient_id or "")
        self.patient_edit.setText(p.get("name",""))
        self.age_edit.setText(p.get("age",""))
        self.gender_edit.setText(p.get("gender",""))
        self.phone_edit.setText(p.get("mobile",""))
        self.email_edit.setText(p.get("email",""))
        self.addr_edit.setText(p.get("address",""))
            
        self._patient_autofill_lock = False

    def _on_patient_name_selected(self, label):
        """Called when user picks 'Name (mobile)' from the autocomplete dropdown."""
        import re
        # Strip the ' (mobile)' suffix to get just the plain name
        plain_name = re.sub(r"\s*\([^)]*\)\s*$", "", label).strip()
        matches = patients_by_name_contains(plain_name)
        # Find exact name match first, then fuzzy
        match = next((r for r in matches if r["name"].lower() == plain_name.lower()), None)
        if not match and matches:
            match = matches[0]
        if match:
            self._fill_patient_fields(match)
        else:
            # No DB match — at least strip the mobile suffix from the field
            self._patient_autofill_lock = True
            self.patient_edit.setText(plain_name)
            self._patient_autofill_lock = False

    def _on_patient_name_typed(self, text):
        """Keep completer fresh; also strip any '(mobile)' the completer auto-inserted."""
        if self._patient_autofill_lock: return
        import re
        # If the completer just wrote a 'Name (digits)' label into the field, strip it immediately
        stripped, count = re.subn(r"\s*\(\d+\)\s*$", "", text)
        if count > 0:
            self._patient_autofill_lock = True
            self.patient_edit.setText(stripped.strip())
            self._patient_autofill_lock = False
            return
        # Refresh completer labels in real-time as user types
        self._name_completer.model().setStringList(all_patient_name_labels())
        self._mobile_completer.model().setStringList(all_patient_mobile_labels())
        self._pid_completer.model().setStringList(all_patient_ids())

    def _on_pid_selected(self, pid):
        """Called when user picks or enters a Patient ID."""
        if self._patient_autofill_lock or not pid.strip(): return
        match = patient_by_id(pid.strip())
        if match:
            self._fill_patient_fields(match)

    def _on_mobile_typed(self, text):
        """Keep mobile completer fresh."""
        if self._patient_autofill_lock: return
        self._mobile_completer.model().setStringList(all_patient_mobile_labels())

    def _on_mobile_selected(self, label):
        """Called when user picks a mobile number from the mobile completer."""
        self.phone_edit.setText(label.strip())
        self._on_mobile_entered()

    def _on_mobile_entered(self):
        """Lookup all patients sharing this mobile; let user pick or skip."""
        if self._patient_autofill_lock: return
        mobile = self.phone_edit.text().strip()
        if not mobile: return
        found = patients_by_mobile(mobile)
        if not found: return

        if len(found) == 1:
            # Single match — ask fill or continue
            p = found[0]
            msg = QMessageBox(self)
            msg.setWindowTitle("Patient Found")
            oa = float(p.get("advance_balance", 0))
            od = float(p.get("due_balance", 0))
            bal_parts = []
            if oa > 0: bal_parts.append(f"<b>Adv: ₹{oa:.2f}</b>")
            if od > 0: bal_parts.append(f"<b style='color:{RED_C}'>Due: ₹{od:.2f}</b>")
            bal_html = f"<br><b>Balance:</b> {' | '.join(bal_parts)}" if bal_parts else ""

            msg.setText(
                f"<b>Mobile {mobile}</b> is already registered.<br><br>"
                f"<b>Patient:</b> {p['name']} &nbsp;|&nbsp; <b>ID:</b> {p['id']}<br>"
                f"<b>Age:</b> {p.get('age','—')} &nbsp; <b>Gender:</b> {p.get('gender','—')}<br>"
                f"<b>Email:</b> {p.get('email','—')}<br>"
                f"<b>Address:</b> {p.get('address','—')}{bal_html}"
            )
            btn_fill = msg.addButton("✔ Fill Details", QMessageBox.ButtonRole.AcceptRole)
            msg.addButton("✕ New Patient", QMessageBox.ButtonRole.RejectRole)
            msg.setDefaultButton(btn_fill)
            msg.exec()
            if msg.clickedButton() == btn_fill:
                self._fill_patient_fields(p)
        else:
            # Multiple family members — show pick-list dialog
            self._pick_patient_dialog(mobile, found)

    def _pick_patient_dialog(self, mobile, patients_list):
        """Show a selection dialog when multiple patients share the same mobile."""
        from PyQt6.QtWidgets import QListWidget, QListWidgetItem
        dlg = QDialog(self)
        dlg.setWindowTitle(f"Multiple Patients — Mobile {mobile}")
        dlg.setMinimumWidth(480)
        lv = QVBoxLayout(dlg); lv.setContentsMargins(20,16,20,16); lv.setSpacing(10)

        info = QLabel(
            f"<b>{len(patients_list)} patients</b> are registered under <b>{mobile}</b>.<br>"
            f"Select the correct patient to auto-fill, or click <i>New Patient</i> to proceed fresh."
        )
        info.setWordWrap(True)
        info.setStyleSheet(f"color:{TP};font-size:13px;background:transparent")
        lv.addWidget(info)

        lst = QListWidget()
        lst.setAlternatingRowColors(True)
        lst.setStyleSheet(f"""
            QListWidget {{ border:1px solid {BORDER}; border-radius:8px;
                          background:{BG_CARD}; font-size:13px; }}
            QListWidget::item {{ padding:8px 12px; }}
            QListWidget::item:selected {{ background:{ACCENT}; color:white; }}
        """)
        for p in patients_list:
            label = f"  {p['name']}   |   ID: {p['id']}"
            item = QListWidgetItem(label)
            item.setData(Qt.ItemDataRole.UserRole, p)
            lst.addItem(item)
        lv.addWidget(lst)

        btns = QHBoxLayout(); btns.setSpacing(8)
        btn_ok  = QPushButton("✔  Fill Selected"); btn_ok.setObjectName("accent")
        btn_new = QPushButton("＋  New Patient");   btn_new.setObjectName("green")
        btn_cancel = QPushButton("✕  Cancel")
        for b in [btn_ok, btn_new, btn_cancel]:
            b.setFixedHeight(32); btns.addWidget(b)
        lv.addLayout(btns)

        def do_fill():
            sel = lst.currentItem()
            if not sel:
                QMessageBox.information(dlg, "Select", "Please select a patient from the list."); return
            self._fill_patient_fields(sel.data(Qt.ItemDataRole.UserRole))
            dlg.accept()

        btn_ok.clicked.connect(do_fill)
        btn_new.clicked.connect(dlg.reject)   # close dialog, keep mobile, let user fill name manually
        btn_cancel.clicked.connect(dlg.reject)
        lst.doubleClicked.connect(lambda _: do_fill())
        dlg.exec()

    def _preview(self):
        d = self._collect()
        dlg = PreviewDialog(build_preview_html(d, self.shop), self)
        dlg.exec()

    def _save(self):
        d = self._collect()
        if not d["patient_name"].strip():
            QMessageBox.warning(self,"Missing Info","Please enter patient name."); return
        
        # Ensure patient exists and get ID BEFORE saving invoice
        # This is CRITICAL for balance updates
        pid = upsert_patient_from_invoice(d)
        d["patient_id"] = pid
        self.current_patient_id = pid
        
        if self.current_invoice_id:
            from PyQt6.QtWidgets import QMessageBox as QMsg
            m = QMsg(self)
            m.setWindowTitle("Update or Save New?")
            m.setText(f"Invoice {d['invoice_no']} already exists.\nDo you want to update the existing record or save it as a new invoice?")
            btn_update = m.addButton("Update Existing", QMsg.ButtonRole.ActionRole)
            btn_new    = m.addButton("Save as New",    QMsg.ButtonRole.ActionRole)
            btn_cancel = m.addButton("Cancel",         QMsg.ButtonRole.RejectRole)
            m.exec()
            
            if m.clickedButton() == btn_update:
                update_invoice(d, self.current_invoice_id)
                QMessageBox.information(self,"✔  Updated",f"Invoice {d['invoice_no']} updated!")
            elif m.clickedButton() == btn_new:
                # Force a new invoice number when saving a copy as new
                d["invoice_no"] = next_invoice_no()
                save_invoice(d)
                QMessageBox.information(self,"✔  Saved",f"New invoice {d['invoice_no']} saved!")
            else:
                return # Cancelled
        else:
            save_invoice(d)
            QMessageBox.information(self,"✔  Saved",f"Invoice {d['invoice_no']} saved!")

        self.invoice_saved.emit()
        self.patient_db_updated.emit()   # notify patients tab
        self._reset()

    def _export_pdf(self):
        d = self._collect()
        path,_ = QFileDialog.getSaveFileName(self,"Export PDF — A5 Invoice",
            f"Invoice_{d['invoice_no'].replace('/','-')}.pdf","PDF Files (*.pdf)")
        if not path: return
        self._pdf_path = path
        self._pdf_web = QWebEngineView()
        self._pdf_web.loadFinished.connect(lambda ok: self._render_pdf())
        self._pdf_web.setHtml(build_single_html(d, self.shop))

    def _render_pdf(self, web=None):
        web = web or self._pdf_web  # backward compat
        layout = QPageLayout(
            QPageSize(QPageSize.PageSizeId.A4),
            QPageLayout.Orientation.Portrait,
            QMarginsF(0, 0, 0, 0)  # CSS @page controls margins
        )

        def _done(path):
            self._cleanup_web(web)  # release reference
            QMessageBox.information(self, "✔  PDF Exported",
                f"Saved — Original Copy on A5:\n{self._pdf_path}")
            try:
                if platform.system() == "Windows":
                    os.startfile(self._pdf_path)
                elif platform.system() == "Darwin":
                    os.system(f'open "{self._pdf_path}"')
            except:
                pass

        # ✅ Connect BEFORE printToPdf
        web.pdfPrintingFinished.connect(_done)
        web.printToPdf(self._pdf_path, layout)

    def _print(self):
        d = self._collect()
        self._print_web = QWebEngineView()
        self._print_web.loadFinished.connect(self._do_print)
        self._print_web.setHtml(build_single_html(d, self.shop, for_print=True))

    def _do_print(self):
        from PyQt6.QtCore import QSizeF
        # A4 portrait — invoice on top half, blank white bottom half
        layout = QPageLayout(
            QPageSize(QPageSize.PageSizeId.A4),
            QPageLayout.Orientation.Portrait,
            QMarginsF(0, 0, 0, 0)
        )
        tmp = os.path.join(os.path.dirname(os.path.abspath(__file__)), "_print_tmp.pdf")

        def _open(path):
            try:
                if platform.system() == "Windows":
                    os.startfile(tmp)
                elif platform.system() == "Darwin":
                    os.system(f'open "{tmp}"')
                else:
                    os.system(f'xdg-open "{tmp}"')
            except:
                pass

        self._print_web.pdfPrintingFinished.connect(_open)
        self._print_web.printToPdf(tmp, layout)

    def load_invoice(self, d):
        self.table.blockSignals(True); self.table.setRowCount(0); self.table.blockSignals(False)
        self.current_invoice_id = d.get("id")  # CRITICAL: Track the ID so _save knows it's an update
        self.current_patient_id = d.get("patient_id")
        self.pid_edit.setText(d.get("patient_id") or "")
        self.patient_edit.setText(d.get("patient_name",""))
        self.age_edit.setText(d.get("patient_age",""))
        self.gender_edit.setText(d.get("patient_gender",""))
        self.phone_edit.setText(d.get("patient_phone",""))
        self.email_edit.setText(d.get("patient_email",""))
        self.addr_edit.setText(d.get("patient_address",""))
        self.remarks_edit.setPlainText(d.get("remarks",""))
        self.invoice_no = d.get("invoice_no","")
        self.inv_badge.setText(self.invoice_no)
        self.date_edit.setText(d.get("date",""))
        
        self.disc_edit.setText(str(d.get("discount_pct",0)))
        self.paid_edit.setText(str(d.get("paid_amount","")))
        for item in d.get("items",[]): self._add_row(item)
        self._recalc()

    def quick_pdf(self, d):
        """Used for direct PDF from history tab."""
        # Need to ensure shop is fresh
        self.shop = get_shop()
        self._export_pdf_direct(d)

    def quick_print(self, d):
        """Used for direct Print from history tab."""
        self.shop = get_shop()
        self._print_direct(d)

    def _export_pdf_direct(self, d):
        path, _ = QFileDialog.getSaveFileName(self, "Export PDF — A5 Invoice",
                                            f"Invoice_{d['invoice_no'].replace('/', '-')}.pdf", "PDF Files (*.pdf)")
        if not path: return
        self._pdf_path = path
        
        web = QWebEngineView()
        self._active_webs = getattr(self, '_active_webs', [])
        self._active_webs.append(web)  # keep alive

        def on_load(ok):
            self._render_pdf(web)     # pass web explicitly

        web.loadFinished.connect(on_load)
        web.setHtml(build_single_html(d, self.shop))

    def _print_direct(self, d):
        web = QWebEngineView()
        self._active_webs = getattr(self, '_active_webs', [])
        self._active_webs.append(web)

        def on_load(ok):
            self._do_print_web(web)

        web.loadFinished.connect(on_load)
        web.setHtml(build_single_html(d, self.shop, for_print=True))

    def _do_print_web(self, web):
        """Print using an explicitly passed QWebEngineView (used by _print_direct)."""
        # A4 portrait — invoice on top half, blank white bottom half
        layout = QPageLayout(
            QPageSize(QPageSize.PageSizeId.A4),
            QPageLayout.Orientation.Portrait,
            QMarginsF(0, 0, 0, 0)
        )
        tmp = os.path.join(os.path.dirname(os.path.abspath(__file__)), "_print_tmp.pdf")

        def _open(path):
            self._cleanup_web(web)
            try:
                if platform.system() == "Windows":
                    os.startfile(tmp)
                elif platform.system() == "Darwin":
                    os.system(f'open "{tmp}"')
                else:
                    os.system(f'xdg-open "{tmp}"')
            except:
                pass

        web.pdfPrintingFinished.connect(_open)
        web.printToPdf(tmp, layout)

    def _cleanup_web(self, web):
        try: self._active_webs.remove(web)
        except: pass

    def refresh_shop(self): self.shop = get_shop()

