        # From date — calendar picker button
        from_lbl = QLabel("FROM")
        from_lbl.setStyleSheet(f"color:{TM};font-size:12px;font-weight:700;letter-spacing:1px;background:transparent")
        self.from_btn = QPushButton("📅  Any date")
        self.from_btn.setFixedWidth(145); self.from_btn.setFixedHeight(34)
