        if patient:
            pid_lbl = QLabel(f"ID: {patient.get('id','')}")
            pid_lbl.setStyleSheet(f"color:{ACCENT};font-size:14px;font-weight:700;"
                                  f"background:{ACCENT_D};border:1px solid {ACCENT}55;"
                                  f"border-radius:6px;padding:3px 12px")
            hdr.addWidget(icon); hdr.addSpacing(6); hdr.addWidget(ttl); hdr.addStretch(); hdr.addWidget(pid_lbl)
