class SettingsTab(QWidget):
    def __init__(self,parent=None):
        super().__init__(parent)
        l=QVBoxLayout(self); l.setContentsMargins(20,18,20,18)
        l.setAlignment(Qt.AlignmentFlag.AlignTop); l.setSpacing(14)
        hdr=QHBoxLayout()
        icon=QLabel("⚙"); icon.setStyleSheet(f"color:{ACCENT};font-size:19px;background:transparent")
        title=QLabel("Shop Settings"); title.setStyleSheet(f"color:{TP};font-size:19px;font-weight:700;background:transparent")
        hdr.addWidget(icon); hdr.addSpacing(8); hdr.addWidget(title); hdr.addStretch()
        l.addLayout(hdr)
        note=QLabel("These details appear on every invoice. Doctor name auto-fills as 'Ref. Doctor' on each bill.")
        note.setStyleSheet(f"color:{TM};font-size:14px;background:transparent"); l.addWidget(note)
        card=QFrame(); card.setObjectName("card"); card.setMaximumWidth(600)
        g=QGridLayout(card); g.setContentsMargins(20,18,20,18); g.setSpacing(12)
        self.fields={}; s=get_shop()
        for i,(k,lb) in enumerate([("shop_name","SHOP NAME"),("store_tag","STORE TAG / SPECIALITY"),
                                    ("dr_name","DOCTOR / PROPRIETOR NAME"),
                                    ("regd_no","REGD. NO. (e.g. IAP/L-13459)"),
                                    ("address1","ADDRESS LINE 1"),
                                    ("address2","ADDRESS LINE 2"),
                                    ("address3","ADDRESS LINE 3 (City, State, PIN)"),
                                    ("phone","MOBILE / PHONE"),
                                    ("website","WEBSITE (e.g. www.example.com)")]):
            g.addWidget(mk_section(lb),i,0); f=QLineEdit(s.get(k,"")); self.fields[k]=f; g.addWidget(f,i,1)
            
        # Add Logo Picker
        g.addWidget(mk_section("SHOP LOGO IMAGE"), 9, 0)
        logow = QWidget(); logow.setStyleSheet("background:transparent")
        logol = QHBoxLayout(logow); logol.setContentsMargins(0,0,0,0); logol.setSpacing(6)
        logo_f = QLineEdit(s.get("logo_path","")); logo_f.setReadOnly(True)
        self.fields["logo_path"] = logo_f
        btn_browse = QPushButton("Browse...")
        btn_browse.setFixedHeight(34); btn_browse.setFixedWidth(80)
        btn_browse.clicked.connect(self._browse_logo)
        btn_clear = QPushButton("✕")
        btn_clear.setFixedHeight(34); btn_clear.setFixedWidth(34)
        btn_clear.clicked.connect(logo_f.clear)
        logol.addWidget(logo_f); logol.addWidget(btn_browse); logol.addWidget(btn_clear)
        g.addWidget(logow, 9, 1)

        l.addWidget(card)
        btn=QPushButton("✔  Save Settings"); btn.setObjectName("accent")
        btn.setFixedWidth(200); btn.setFixedHeight(40); btn.clicked.connect(self._save); l.addWidget(btn)

    def _browse_logo(self):
        path, _ = QFileDialog.getOpenFileName(self, "Select Shop Logo", "", "Images (*.png *.jpg *.jpeg)")
        if path: self.fields["logo_path"].setText(path)

    def _save(self):
        conn=sqlite3.connect(DB_PATH); c=conn.cursor()
        c.execute("UPDATE shop_settings SET shop_name=?,store_tag=?,dr_name=?,regd_no=?,address1=?,address2=?,address3=?,phone=?,website=?,logo_path=? WHERE id=1",
            tuple(self.fields[k].text() for k in ["shop_name","store_tag","dr_name","regd_no","address1","address2","address3","phone","website","logo_path"]))
        conn.commit(); conn.close()
        QMessageBox.information(self,"✔  Saved","Settings saved successfully!")

