def main():
    init_db()
    app = QApplication(sys.argv)
    # Auto-scale UI based on screen width
    # Reference width = 1920px (your big laptop)
    # Small laptop ~1366px will scale down fonts/padding automatically
    screen = app.primaryScreen()
    screen_w = screen.availableGeometry().width()
    screen_h = screen.availableGeometry().height()
    scale = max(0.75, min(1.0, screen_w / 1920))
    global UI_SCALE
    UI_SCALE = scale
    app.setStyleSheet(build_stylesheet(scale))
    win = MainWindow()
    win.showMaximized()   # open full screen on launch
    sys.exit(app.exec())

if __name__ == "__main__":
    main()